import { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "../assets/css/dashboard.css";

function Dashboard() {
  const [data, setData] = useState({});
  const navigate = useNavigate();

  const token = localStorage.getItem("token");

  useEffect(() => {
    const fetchDashboard = async () => {
      try {
        const res = await axios.get(
          "http://localhost:5001/api/dashboard/stats",
          {
            headers: {
              Authorization: `Bearer ${token}`,
            },
          }
        );

        setData(res.data);
      } catch (err) {
        console.log("Dashboard Error:", err);
      }
    };

    fetchDashboard();
  }, []);

  return (
    <div className="dashboard-container">

      <h1 className="dashboard-title">
        📊 Dashboard Overview
      </h1>

      {/* CARDS */}
      <div className="card-grid">
        <div className="card blue">
          <h3>Customers</h3>
          <h2>{data.totalCustomers || 0}</h2>
        </div>

        <div className="card green">
          <h3>Products</h3>
          <h2>{data.totalProducts || 0}</h2>
        </div>

        <div className="card orange">
          <h3>Invoices</h3>
          <h2>{data.totalInvoices || 0}</h2>
        </div>

        <div className="card purple">
          <h3>Revenue</h3>
          <h2>₹{data.totalRevenue || 0}</h2>
        </div>
      </div>

      {/* SECOND ROW */}
      <div className="grid-2">

        <div className="card warning">
          <h3>⚠ Low Stock Alert</h3>
          <h2>{data.lowStockCount || 0}</h2>
          <p>Items need restocking</p>
        </div>

        {/* QUICK ACTIONS */}
        <div className="card actions">
          <h3>Quick Actions</h3>

          <button onClick={() => navigate("/billing/customers")}>
            ➕ Add Customer
          </button>

          <button onClick={() => navigate("/billing/products")}>
            📦 Add Product
          </button>

          <button onClick={() => navigate("/billing/invoices")}>
            🧾 Create Invoice
          </button>
        </div>

      </div>

      {/* ACTIVITY */}
      <div className="card activity">
        <h3>Recent Activity</h3>
        <ul>
          <li>📄 Invoice generated</li>
          <li>📦 Stock updated</li>
          <li>👤 Customer added</li>
        </ul>
      </div>

    </div>
  );
}

export default Dashboard;